<template>
    <div>
        Dashboard
        <br>
        <button class="btn btn-danger" @click="signout">Logout</button>
        <br>
        
        Welcome {{ user.email }}
        {{ site }}
        <form class="col-md-6 col-md-offset-3">
            <div class="form-group row">
                <label for="title" class="col-sm-2 col-form-label">Title</label>
                <div class="col-sm-10">
                    <input type="text" class="form-control" id="title" v-model="site.title">
                </div>
            </div>
            <div class="form-group row">
                <label for="header" class="col-sm-2 col-form-label">Header</label>
                <div class="col-sm-10">
                    <input type="text" class="form-control" id="header" v-model="site.header">
                </div>
            </div>
            <div class="form-group row">
                <label for="sub_header" class="col-sm-2 col-form-label">Sub Header</label>
                <div class="col-sm-10">
                    <input type="text" class="form-control" id="sub_header" v-model="site.sub_header">
                </div>
            </div>
             <div class="form-group row">
                 <label for="inputPassword" class="col-sm-2 col-form-label"></label>
                <div class="col-sm-10">
                    <button @click="update" type="button" class="pull-left btn btn-primary">Update</button>
                </div>
            </div>
        </form>
        
        <!-- <button @click="submit">A</button> -->
    </div>
</template>

<script>

import { siteRef,firebaseApp } from '../firebaseapp'

export default {
    data(){
        return{
            site:{
                title:'',
                header:'',
                sub_header:''
            },
            test:{}
        }
    },
    computed:{
        user(){
            return this.$store.getters.user;
        }
    },
    methods:{
        submit(){
            siteRef.push(this.site);
        },
        signout(){
            firebaseApp.auth().signOut()
            .then(success => {
                this.$store.commit('logout')
                this.$router.replace('/')
            });
        },
        update(){
            siteRef.update(this.site);
        }
    },
    mounted(){
        // siteRef.orderByKey().limitToFirst(1).once('value',snap => {
        //     this.test = snap.val();
        //     // console.log(snap.val());
        //     snap.forEach(event =>{
        //         console.log(event.val());
        //         this.site = event.val();
        //     })
        // })
        siteRef.on('value',snap => {
            this.site = snap.val();
        })
    }
}
</script>

