import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    user:{}
  },
  getters:{
    user(state){
      return state.user;
    }
  },
  mutations: {
      login(state,payload){
        state.user = payload;
      },
      logout(state){
        state.user = {};
      }
  },
  actions: {
  }
})
